import React from 'react';
import { GamePhase } from '../types';

interface BetPanelProps {
  betAmount: number;
  selectedChicken: number | null;
  phase: GamePhase;
  balance: number;
  onBetChange: (amount: number) => void;
  onSelectChicken: (id: number) => void;
  onRandomChoice: () => void;
  onStartRace: () => void;
  winner: number | null;
  resultMessage: string;
}

const PRESET_BETS = [50, 100, 250, 500];
const MIN_BET = 50;
const MAX_BET = 500;
const BET_STEP = 50;

const BetPanel: React.FC<BetPanelProps> = ({
  betAmount,
  selectedChicken,
  phase,
  balance,
  onBetChange,
  onSelectChicken,
  onRandomChoice,
  onStartRace,
  winner,
  resultMessage,
}) => {
  const canBet = phase === 'betting' || phase === 'result';
  const canStart = phase === 'betting' && selectedChicken !== null;

  const handleDecrement = () => {
    if (betAmount > MIN_BET) {
      onBetChange(Math.max(MIN_BET, betAmount - BET_STEP));
    }
  };

  const handleIncrement = () => {
    if (betAmount < MAX_BET) {
      onBetChange(Math.min(MAX_BET, betAmount + BET_STEP));
    }
  };

  return (
    <div className="bet-panel">
      {/* Grass texture top */}
      <div className="bet-panel-grass" />

      <div className="bet-panel-content">
        {/* Chicken selector */}
        <div className="chicken-selector">
          <span className="selector-label">Pick a lane:</span>
          <div className="selector-buttons">
            {[1, 2, 3, 4].map((id) => (
              <button
                key={id}
                className={`lane-btn ${selectedChicken === id ? 'lane-btn-active' : ''}`}
                onClick={() => canBet && onSelectChicken(id)}
                disabled={!canBet}
                aria-label={`Select lane ${id}`}
              >
                {id}
              </button>
            ))}
          </div>
        </div>

        {/* Divider */}
        <div className="bet-divider" />

        {/* Bet amount controls */}
        <div className="bet-controls">
          <button
            className="bet-ctrl-btn bet-minmax"
            onClick={() => canBet && onBetChange(MIN_BET)}
            disabled={!canBet}
            aria-label="Minimum bet"
          >
            MIN
          </button>
          <button
            className="bet-ctrl-btn bet-stepper"
            onClick={handleDecrement}
            disabled={!canBet || betAmount <= MIN_BET}
            aria-label="Decrease bet"
          >
            −
          </button>
          <div className="bet-display">
            <span className="bet-amount">{betAmount.toLocaleString()}</span>
            <span className="bet-currency">$</span>
          </div>
          <button
            className="bet-ctrl-btn bet-stepper"
            onClick={handleIncrement}
            disabled={!canBet || betAmount >= MAX_BET}
            aria-label="Increase bet"
          >
            +
          </button>
          <button
            className="bet-ctrl-btn bet-minmax"
            onClick={() => canBet && onBetChange(MAX_BET)}
            disabled={!canBet}
            aria-label="Maximum bet"
          >
            MAX
          </button>
        </div>

        {/* Preset bet buttons */}
        <div className="preset-bets">
          {PRESET_BETS.map((preset) => (
            <button
              key={preset}
              className={`preset-btn ${betAmount === preset ? 'preset-btn-active' : ''}`}
              onClick={() => canBet && onBetChange(preset)}
              disabled={!canBet}
              aria-label={`Bet ${preset}`}
            >
              {preset}
            </button>
          ))}
        </div>

        {/* Divider */}
        <div className="bet-divider" />

        {/* Result message */}
        {phase === 'result' && resultMessage && (
          <div className={`result-message ${resultMessage.includes('Win') ? 'result-win' : 'result-lose'}`}>
            {resultMessage}
          </div>
        )}

        {/* Action buttons */}
        <div className="action-buttons">
          {canStart && (
            <button
              className="start-btn"
              onClick={onStartRace}
              aria-label="Start race"
            >
              🏁 START RACE
            </button>
          )}
          <button
            className="random-btn"
            onClick={onRandomChoice}
            disabled={!canBet}
            aria-label="Random choice"
          >
            🎲 RANDOM CHOICE
          </button>
        </div>
      </div>
    </div>
  );
};

export default BetPanel;
